138	    @Override
139	    public PageResult<MonthlyInspectionPageBO> monthlyInspection(MonthlyInspectionQueryBO queryBO) {
140	        Page<HseMonthlyInspectionEntity> page = new Page<>(queryBO.getPageNum(), queryBO.getPageSize());
141	        LambdaQueryWrapper<HseMonthlyInspectionEntity> queryWrapper = new LambdaQueryWrapper<>();
142	
143	        // 筛选条件
144	        if (queryBO.getStatus() != null) {
145	            queryWrapper.eq(HseMonthlyInspectionEntity::getStatus, queryBO.getStatus());
146	        }
147	        if (queryBO.getStartDate() != null && queryBO.getEndDate() != null) {
148	            queryWrapper.between(HseMonthlyInspectionEntity::getInspectionDate, queryBO.getStartDate(),
149	                    queryBO.getEndDate());
150	        } else if (queryBO.getStartDate() != null) {
151	            queryWrapper.ge(HseMonthlyInspectionEntity::getInspectionDate, queryBO.getStartDate());
152	        } else if (queryBO.getEndDate() != null) {
153	            queryWrapper.le(HseMonthlyInspectionEntity::getInspectionDate, queryBO.getEndDate());
154	        }
155	
156	        queryWrapper.orderByDesc(HseMonthlyInspectionEntity::getCreateTime);
157	
158	        // 分页查询
159	        IPage<HseMonthlyInspectionEntity> pageResult = this.page(page, queryWrapper);
160	
161	        if (CollectionUtils.isEmpty(pageResult.getRecords())) {
162	            return PageResult.empty();
163	        }
164	
165	        // 批量查询关联数据 - 查询每个巡检的问题数量
166	        List<Long> monthlyInspectionIds = pageResult.getRecords()
167	                .stream()
168	                .map(HseMonthlyInspectionEntity::getMonthlyInspectionId)
169	                .collect(Collectors.toList());
170	
171	        LambdaQueryWrapper<HseCorrectiveActionsEntity> correctiveQueryWrapper = new LambdaQueryWrapper<>();
172	        correctiveQueryWrapper.in(HseCorrectiveActionsEntity::getMonthlyInspectionId, monthlyInspectionIds);
173	        List<HseCorrectiveActionsEntity> correctiveActionsList =
174	                hseCorrectiveActionsService.list(correctiveQueryWrapper);
175	
176	        // 统计每个巡检的问题数量
177	        Map<Long, Long> issuesCountMap = correctiveActionsList.stream()
178	                .collect(Collectors.groupingBy(HseCorrectiveActionsEntity::getMonthlyInspectionId, Collectors.counting()));
179	
180	        List<Long> inspectorIds =
181	                pageResult.getRecords().stream().map(HseMonthlyInspectionEntity::getInspector).collect(Collectors.toList());
182	        List<UserEntity> userEntityList = userService.getUserByUserIdList(inspectorIds);
183	        Map<Long, UserEntity> userEntityMap =
184	                userEntityList.stream().collect(Collectors.toMap(UserEntity::getUserId, Function.identity()));
185	        // 组装数据
186	        List<MonthlyInspectionPageBO> boList = new ArrayList<>();
187	        for (HseMonthlyInspectionEntity entity : pageResult.getRecords()) {
188	            MonthlyInspectionPageBO bo = new MonthlyInspectionPageBO();
189	            bo.setMonthlyInspectionId(entity.getMonthlyInspectionId());
190	            bo.setInspectionDate(entity.getInspectionDate());
191	            bo.setInspector(entity.getInspector());
192	            UserEntity userEntity = userEntityMap.get(entity.getInspector());
193	            if (userEntity != null) {
194	                bo.setInspectorName(userEntity.getFullName());
195	                bo.setInspectorNameAr(userEntity.getFullNameAr());
196	            }
197	            bo.setStatus(entity.getStatus());
198	            bo.setIssuesObserved(issuesCountMap.getOrDefault(entity.getMonthlyInspectionId(), 0L).intValue());
199	            boList.add(bo);
200	        }
201	
202	        return new PageResult<>(boList, pageResult.getTotal());
203	    }
