205	    @Override
206	    public Long monthlyInspectionSave(MonthlyInspectionSaveBO saveBO) {
207	        HseMonthlyInspectionEntity hseMonthlyInspectionEntity = new HseMonthlyInspectionEntity();
208	        hseMonthlyInspectionEntity.setMonthlyInspectionId(IdWorker.getId());
209	        hseMonthlyInspectionEntity.setInspectionDate(saveBO.getInspectionDate());
210	        hseMonthlyInspectionEntity.setInspector(saveBO.getInspector());
211	        hseMonthlyInspectionEntity.setStatus(MonthlyInspectionStatusEnum.DRAFT.getCode());
212	        this.save(hseMonthlyInspectionEntity);
213	
214	        List<Long> sectionIds = hseSectionService.list().stream()
215	                .map(HseSectionEntity::getSectionId).collect(Collectors.toList());
216	
217	        List<HseInspectionDormSetupEntity> dormSetupList = sectionIds.isEmpty()
218	                ? Collections.emptyList()
219	                : hseInspectionDormSetupService.list(new LambdaQueryWrapper<HseInspectionDormSetupEntity>()
220	                        .in(HseInspectionDormSetupEntity::getSectionId, sectionIds));
221	
222	        // 每个 dorm × 每个楼层（Around -1 / Inside 0-8 / Parking 9-11）都展开一行 answer
223	        // 同时落对应的 floor_status 初始行
224	        Long monthlyInspectionId = hseMonthlyInspectionEntity.getMonthlyInspectionId();
225	        InspectionInsideFloorEnum[] allFloors = InspectionInsideFloorEnum.values();
226	        List<HseInspectionAnswerEntity> hseInspectionAnswerEntities =
227	                new ArrayList<>(dormSetupList.size() * allFloors.length);
228	        List<HseInspectionFloorStatusEntity> floorStatusRows = new ArrayList<>(allFloors.length);
229	        for (InspectionInsideFloorEnum floor : allFloors) {
230	            floorStatusRows.add(buildFloorStatusInitRow(
231	                    monthlyInspectionId, floor.getTabType().getCode(), floor.getCode()));
232	            for (HseInspectionDormSetupEntity hseInspectionDormSetupEntity : dormSetupList) {
233	                hseInspectionAnswerEntities.add(buildAnswerEntity(
234	                        monthlyInspectionId, hseInspectionDormSetupEntity, floor.getCode()));
235	            }
236	        }
237	        if (!hseInspectionAnswerEntities.isEmpty()) {
238	            hseInspectionAnswerService.saveBatch(hseInspectionAnswerEntities);
239	        }
240	        floorStatusService.saveBatch(floorStatusRows);
241	
242	        return hseMonthlyInspectionEntity.getMonthlyInspectionId();
243	    }
