245	    @Override
246	    public MonthlyInspectionDetailOutput monthlyInspectionDetail(MonthlyInspectionDetailInput input) {
247	        Long monthlyInspectionId = input.getMonthlyInspectionId();
248	        LambdaQueryWrapper<HseMonthlyInspectionEntity> hseMonthlyInspectionEntityLambdaQueryWrapper =
249	                new LambdaQueryWrapper<>();
250	        hseMonthlyInspectionEntityLambdaQueryWrapper.eq(HseMonthlyInspectionEntity::getMonthlyInspectionId,
251	                monthlyInspectionId);
252	        HseMonthlyInspectionEntity hseMonthlyInspectionEntity =
253	                this.getOne(hseMonthlyInspectionEntityLambdaQueryWrapper);
254	        if (hseMonthlyInspectionEntity == null) {
255	            return new MonthlyInspectionDetailOutput();
256	        }
257	        MonthlyInspectionDetailOutput output = new MonthlyInspectionDetailOutput();
258	        output.setInspectionDate(hseMonthlyInspectionEntity.getInspectionDate());
259	        output.setInspector(hseMonthlyInspectionEntity.getInspector());
260	        output.setTypeStep(hseMonthlyInspectionEntity.getTypeStep());
261	        output.setType(input.getType());
262	        output.setFloorCode(input.getFloor());
263	        UserEntity userByUserId = userService.getUserByUserId(hseMonthlyInspectionEntity.getInspector());
264	        if (userByUserId != null) {
265	            output.setInspectorName(userByUserId.getFullName());
266	            output.setInspectorNameAr(userByUserId.getFullNameAr());
267	        }
268	        output.setMonthlyInspectionId(hseMonthlyInspectionEntity.getMonthlyInspectionId());
269	
270	        LambdaQueryWrapper<HseInspectionAnswerEntity> hseInspectionAnswerEntityLambdaQueryWrapper =
271	                new LambdaQueryWrapper<>();
272	        hseInspectionAnswerEntityLambdaQueryWrapper.eq(HseInspectionAnswerEntity::getMonthlyInspectionId,
273	                monthlyInspectionId);
274	        List<HseInspectionAnswerEntity> hseInspectionAnswerEntityList =
275	                hseInspectionAnswerService.list(hseInspectionAnswerEntityLambdaQueryWrapper);
276	        if (hseInspectionAnswerEntityList.isEmpty()) {
277	            return output;
278	        }
279	
280	        List<Long> sectionIdsForRepair = hseInspectionAnswerEntityList.stream()
281	                .map(HseInspectionAnswerEntity::getSectionId)
282	                .filter(Objects::nonNull)
283	                .distinct()
284	                .collect(Collectors.toList());
285	        Map<Long, HseSectionEntity> sectionMapForRepair = hseSectionService
286	                .listBySectionIdsIncludeDeleted(sectionIdsForRepair).stream()
287	                .collect(Collectors.toMap(HseSectionEntity::getSectionId, Function.identity(), (a, b) -> a));
288	        if (repairMissingFloorExpansion(monthlyInspectionId, hseInspectionAnswerEntityList, sectionMapForRepair)) {
289	            hseInspectionAnswerEntityList =
290	                    hseInspectionAnswerService.list(hseInspectionAnswerEntityLambdaQueryWrapper);
291	        }
292	
293	        List<Long> sectionIds = hseInspectionAnswerEntityList.stream()
294	                .map(HseInspectionAnswerEntity::getSectionId)
295	                .filter(Objects::nonNull)
296	                .distinct()
297	                .collect(Collectors.toList());
298	        List<HseSectionEntity> hseSectionEntityList = hseSectionService.listBySectionIdsIncludeDeleted(sectionIds);
299	        Map<Long, HseSectionEntity> sectionMap = hseSectionEntityList.stream()
300	                .collect(Collectors.toMap(HseSectionEntity::getSectionId, Function.identity(), (a, b) -> a));
301	
302	        List<Long> dormSetupIds = hseInspectionAnswerEntityList.stream()
303	                .map(HseInspectionAnswerEntity::getDormSetupId)
304	                .filter(Objects::nonNull)
305	                .distinct()
306	                .collect(Collectors.toList());
307	        List<HseInspectionDormSetupEntity> hseInspectionDormSetupEntityList =
308	                hseInspectionDormSetupService.listByDormSetupIdsIncludeDeleted(dormSetupIds);
309	        Map<Long, HseInspectionDormSetupEntity> dormSetupMap = hseInspectionDormSetupEntityList.stream()
310	                .collect(Collectors.toMap(HseInspectionDormSetupEntity::getDormSetupId, Function.identity(), (a, b) -> a));
311	
312	        Set<Long> orgIds = new HashSet<>();
313	        hseSectionEntityList.stream().map(HseSectionEntity::getOrgId).filter(Objects::nonNull).forEach(orgIds::add);
314	        hseInspectionDormSetupEntityList.stream().map(HseInspectionDormSetupEntity::getOrgId).filter(Objects::nonNull)
315	                .forEach(orgIds::add);
316	        Map<Long, OrganizationEntity> orgMap = Collections.emptyMap();
317	        if (!orgIds.isEmpty()) {
318	            LambdaQueryWrapper<OrganizationEntity> organizationEntityLambdaQueryWrapper = new LambdaQueryWrapper<>();
319	            organizationEntityLambdaQueryWrapper.in(OrganizationEntity::getOrgId, orgIds);
320	            List<OrganizationEntity> orgList = organizationService.list(organizationEntityLambdaQueryWrapper);
321	            orgMap = orgList.stream().collect(Collectors.toMap(OrganizationEntity::getOrgId, Function.identity()));
322	        }
323	
324	        Integer typeFilter = input.getType();
325	        Integer floorFilter = input.getFloor();
326	
327	        List<InspectionAnswerOutput> answerOutputs = new ArrayList<>();
328	        for (HseInspectionAnswerEntity hseInspectionAnswerEntity : hseInspectionAnswerEntityList) {
329	            InspectionAnswerOutput answerOutput = new InspectionAnswerOutput();
330	            answerOutput.setMonthlyInspectionId(hseInspectionAnswerEntity.getMonthlyInspectionId());
331	            answerOutput.setInspectionAnswerId(hseInspectionAnswerEntity.getInspectionAnswerId());
332	            answerOutput.setSectionId(hseInspectionAnswerEntity.getSectionId());
333	            answerOutput.setDormSetupId(hseInspectionAnswerEntity.getDormSetupId());
334	            Integer isSituation = resolveDisplayIsSituation(hseInspectionAnswerEntity.getIsSituation());
335	            answerOutput.setIsSituation(isSituation);
336	            if (IsSituationEnum.YES.getCode().equals(isSituation)) {
337	                answerOutput.setRemarks(null);
338	                answerOutput.setRemarksAr(null);
339	                answerOutput.setAttachmentList(new ArrayList<>());
340	                answerOutput.setCorrectiveActionInfo(new ArrayList<>());
341	            } else {
342	                answerOutput.setRemarks(hseInspectionAnswerEntity.getRemarks());
343	                answerOutput.setRemarksAr(hseInspectionAnswerEntity.getRemarksAr());
344	                applyMonthlyDetailFindingsAndAttachments(answerOutput, hseInspectionAnswerEntity,
345	                        answerOutput.getDefaultResponsibleOrgId());
346	            }
347	            HseSectionEntity hseSectionEntity = sectionMap.get(hseInspectionAnswerEntity.getSectionId());
348	            if (hseSectionEntity != null) {
349	                answerOutput.setSectionName(hseSectionEntity.getName());
350	                answerOutput.setSectionNameAr(hseSectionEntity.getNameAr());
