372	            // type/floor 过滤：type 为空不过滤；type=1(Around) 不按 floor 过滤；floor 为空或 -1 也不过滤
373	            if (typeFilter != null && !Objects.equals(hseInspectionAnswerEntity.getType(), typeFilter)) {
