377	                    && floorFilter != null && floorFilter != -1
378	                    && !Objects.equals(hseInspectionAnswerEntity.getFloorCode(), floorFilter)) {
379	                continue;
380	            }
381	
382	            answerOutputs.add(answerOutput);
383	        }
384	        output.setInspectionAnswerList(answerOutputs);
385	        return output;
