785	        LambdaQueryWrapper<HseCorrectiveActionsEntity> caQuery = new LambdaQueryWrapper<>();
786	        caQuery.eq(HseCorrectiveActionsEntity::getInspectionAnswerId, hseInspectionAnswerEntity.getInspectionAnswerId());
787	        caQuery.orderByDesc(HseCorrectiveActionsEntity::getPrimaryFinding);
788	        caQuery.orderByAsc(HseCorrectiveActionsEntity::getCorrectiveActionsId);
789	        List<HseCorrectiveActionsEntity> caList = hseCorrectiveActionsService.list(caQuery);
790	        if (!caList.isEmpty()) {
791	            List<CorrectiveActionInfoOutput> infoList = new ArrayList<>();
792	            for (HseCorrectiveActionsEntity ca : caList) {
793	                CorrectiveActionInfoOutput info = new CorrectiveActionInfoOutput();
794	                info.setCorrectiveActionsId(ca.getCorrectiveActionsId());
795	                info.setCorrectiveAction(ca.getCorrectiveAction());
796	                info.setCorrectiveActionAr(ca.getCorrectiveActionAr());
797	                Long findingOrgId = ca.getOrgId() != null ? ca.getOrgId() : defaultResponsibleOrgId;
798	                info.setOrgId(findingOrgId);
799	                if (findingOrgId != null) {
800	                    OrgDetailBO detail = organizationService.detail(findingOrgId);
801	                    if (detail != null) {
802	                        info.setOrg(detail);
803	                    }
804	                }
805	                info.setFindingRemarks(ca.getFindingRemarks());
806	                info.setFindingRemarksAr(ca.getFindingRemarksAr());
807	                info.setTargetClosureDate(ca.getTargetClosureDate());
808	                info.setPrimaryFinding(ca.getPrimaryFinding());
809	                List<AttachmentEntity> caAttaches = attachmentService.list(Wrappers.lambdaQuery(AttachmentEntity.class)
810	                        .eq(AttachmentEntity::getBizId, ca.getCorrectiveActionsId())
