847	            hseInspectionAnswerService.updateById(hseInspectionAnswerEntity);
848	            processAttachment(hseInspectionAnswerEntity.getInspectionAnswerId(), Collections.emptyList(),
849	                    AttachTypeEnum.INSPECTION_ANSWER);
850	            return;
851	        }
852	
853	        if (IsSituationEnum.NO.getCode().equals(isSituation)) {
854	            if (CollectionUtils.isNotEmpty(inspectionAnswerSaveBO.getFindings())) {
855	                InspectionFindingSaveBO first = inspectionAnswerSaveBO.getFindings().get(0);
856	                hseInspectionAnswerEntity.setRemarks(first.getFindingRemarks());
