866	            return;
867	        }
868	
869	        // NA
870	        hseCorrectiveActionsService.removeCorrectiveActionsByInspectionAnswerId(
871	                hseInspectionAnswerEntity.getInspectionAnswerId());
872	        hseInspectionAnswerService.updateById(hseInspectionAnswerEntity);
