914	    /**
915	     * 历史数据：Inside/Parking 未按楼层展开时，在详情加载时补全 G/M/1–6/RF。
916	     */
917	    private boolean repairMissingFloorExpansion(Long monthlyInspectionId,
918	                                                List<HseInspectionAnswerEntity> answerList,
919	                                                Map<Long, HseSectionEntity> sectionMap) {
920	        List<Long> removeIds = new ArrayList<>();
921	        List<HseInspectionAnswerEntity> toAdd = new ArrayList<>();
922	        Map<Long, Long> oldToPrimaryNewId = new HashMap<>();
923	
924	        for (HseInspectionAnswerEntity answer : answerList) {
925	            if (answer.getFloorCode() != null) {
926	                continue;
927	            }
928	            HseSectionEntity section = sectionMap.get(answer.getSectionId());
929	            if (section == null) {
930	                continue;
931	            }
932	            List<Integer> floors = resolveFloorCodesForSectionType(section.getType());
933	            if (floors.isEmpty()) {
934	                continue;
935	            }
936	            removeIds.add(answer.getInspectionAnswerId());
937	            Long primaryNewId = null;
938	            for (Integer floor : floors) {
939	                HseInspectionAnswerEntity expanded = copyAnswerWithFloor(answer, floor);
940	                if (primaryNewId == null) {
941	                    primaryNewId = expanded.getInspectionAnswerId();
942	                }
943	                toAdd.add(expanded);
944	            }
945	            oldToPrimaryNewId.put(answer.getInspectionAnswerId(), primaryNewId);
946	        }
947	
948	        if (removeIds.isEmpty()) {
949	            return false;
950	        }
951	
952	        for (Map.Entry<Long, Long> entry : oldToPrimaryNewId.entrySet()) {
953	            LambdaUpdateWrapper<HseCorrectiveActionsEntity> caUpdate = new LambdaUpdateWrapper<>();
954	            caUpdate.eq(HseCorrectiveActionsEntity::getInspectionAnswerId, entry.getKey())
955	                    .set(HseCorrectiveActionsEntity::getInspectionAnswerId, entry.getValue());
956	            hseCorrectiveActionsService.update(caUpdate);
957	            List<AttachmentEntity> attachments = attachmentService.list(Wrappers.lambdaQuery(AttachmentEntity.class)
958	                    .eq(AttachmentEntity::getBizId, entry.getKey())
959	                    .eq(AttachmentEntity::getBizType, AttachTypeEnum.INSPECTION_ANSWER.getCode()));
960	            if (CollectionUtils.isNotEmpty(attachments)) {
961	                processAttachment(entry.getValue(), AttachConverter.toAttachDtoList(attachments),
962	                        AttachTypeEnum.INSPECTION_ANSWER);
963	            }
964	        }
965	
966	        hseInspectionAnswerService.remove(new LambdaQueryWrapper<HseInspectionAnswerEntity>()
967	                .eq(HseInspectionAnswerEntity::getMonthlyInspectionId, monthlyInspectionId)
968	                .in(HseInspectionAnswerEntity::getInspectionAnswerId, removeIds));
969	        hseInspectionAnswerService.saveBatch(toAdd);
970	        return true;
971	    }
