990	    @Override
991	    public List<InspectionTabSummaryOutput> findingCount(MonthlyInspectionIdentityInput input) {
992	        Long monthlyInspectionId = input.getMonthlyInspectionId();
993	
994	        // 1) 拉本次巡检的全部 answer（answer.type 直接给出所属 Tab，省一次 section 查询）
995	        List<HseInspectionAnswerEntity> answers = inspectionAnswerService.list(
996	                new LambdaQueryWrapper<HseInspectionAnswerEntity>()
997	                        .eq(HseInspectionAnswerEntity::getMonthlyInspectionId, monthlyInspectionId));
998	
999	        // 2) corrective_actions 按 inspection_answer_id 计数
1000	        List<Long> answerIds = answers.stream()
1001	                .map(HseInspectionAnswerEntity::getInspectionAnswerId)
1002	                .filter(Objects::nonNull)
1003	                .collect(Collectors.toList());
1004	        Map<Long, Long> findingCountByAnswerId = answerIds.isEmpty()
1005	                ? Collections.emptyMap()
1006	                : hseCorrectiveActionsService.list(new LambdaQueryWrapper<HseCorrectiveActionsEntity>()
1007	                                .in(HseCorrectiveActionsEntity::getInspectionAnswerId, answerIds))
1008	                        .stream()
1009	                        .filter(ca -> ca.getInspectionAnswerId() != null)
1010	                        .collect(Collectors.groupingBy(HseCorrectiveActionsEntity::getInspectionAnswerId,
1011	                                Collectors.counting()));
1012	
1013	        // 3) 在内存聚合到 (type, floorCode)
1014	        Map<Integer, Long> tabTotalByType = new HashMap<>();
1015	        Map<Integer, Map<Integer, Long>> floorTotalByType = new HashMap<>();
1016	        for (HseInspectionAnswerEntity ans : answers) {
1017	            Integer type = ans.getType();
1018	            if (type == null) {
1019	                continue;
1020	            }
1021	            long cnt = findingCountByAnswerId.getOrDefault(ans.getInspectionAnswerId(), 0L);
1022	            tabTotalByType.merge(type, cnt, Long::sum);
1023	            Integer floorCode = ans.getFloorCode();
1024	            if (floorCode != null) {
1025	                floorTotalByType.computeIfAbsent(type, k -> new HashMap<>()).merge(floorCode, cnt, Long::sum);
1026	            }
1027	        }
1028	
1029	        // 5) 装配 3 个 tab 输出
1030	        List<InspectionTabSummaryOutput> result = new ArrayList<>();
1031	        for (InspectionFormSetupTypeEnum tab : InspectionFormSetupTypeEnum.values()) {
1032	            Integer typeCode = tab.getCode();
1033	            InspectionTabSummaryOutput tabSummary = new InspectionTabSummaryOutput();
1034	            tabSummary.setType(typeCode);
1035	            tabSummary.setFindingCount(tabTotalByType.getOrDefault(typeCode, 0L).intValue());
1036	
1037	            if (InspectionFormSetupTypeEnum.INSIDE_THE_BUILDING.getCode().equals(typeCode)
1038	                    || InspectionFormSetupTypeEnum.PARKING.getCode().equals(typeCode)) {
1039	                List<InspectionFloorSummaryOutput> floorSummaryList = new ArrayList<>();
1040	                Map<Integer, Long> floorCounts = floorTotalByType.getOrDefault(typeCode, Collections.emptyMap());
1041	                for (Map.Entry<Integer, Long> e : floorCounts.entrySet()) {
1042	                    InspectionFloorSummaryOutput floorSummary = new InspectionFloorSummaryOutput();
1043	                    floorSummary.setType(typeCode);
1044	                    floorSummary.setFloorCode(e.getKey());
1045	                    floorSummary.setFindingCount(e.getValue().intValue());
1046	                    floorSummaryList.add(floorSummary);
1047	                }
1048	                tabSummary.setFloorSummaryList(floorSummaryList);
1049	            }
1050	            result.add(tabSummary);
1051	        }
1052	        return result;
1053	    }
