134	    public void sectionSave(SectionSaveTypeBO saveBO) {
135	        validateSectionSavePayload(saveBO);
136	        validateSectionAndItemNames(saveBO.getSections());
137	
138	        // 查询该类型下的所有旧分区
139	        LambdaQueryWrapper<HseSectionEntity> hseSectionEntityLambdaQueryWrapper = new LambdaQueryWrapper<>();
140	        hseSectionEntityLambdaQueryWrapper.eq(HseSectionEntity::getType, saveBO.getType());
141	        List<HseSectionEntity> oldSections = list(hseSectionEntityLambdaQueryWrapper);
142	
143	        // 将旧分区转换为Map，方便查找
144	        Map<Long, HseSectionEntity> oldSectionMap = oldSections.stream()
145	                .collect(Collectors.toMap(HseSectionEntity::getSectionId, section -> section, (v1, v2) -> v1));
146	
147	        List<SectionSaveBO> newSections = saveBO.getSections();
148	
149	        for (SectionSaveBO newSection : newSections) {
150	            Long sectionId = newSection.getSectionId();
151	
152	            if (sectionId == null) {
153	                // 新增分区
154	                HseSectionEntity sectionEntity = new HseSectionEntity();
155	                BeanUtil.copyProperties(newSection, sectionEntity);
156	                sectionEntity.setType(saveBO.getType());
157	                sectionEntity.setSectionId(IdWorker.getId());
158	                this.save(sectionEntity);
159	
160	                // 更新sectionId为生成的值
161	                sectionId = sectionEntity.getSectionId();
162	
163	                // 保存检查项
164	                saveItems(newSection.getItems(), sectionId);
165	            } else {
166	                // 修改分区：分区文案/责任部门变更时软删旧行并新建 sectionId，避免历史巡检仍指向旧 id 却展示新模板名
167	                HseSectionEntity oldSection = oldSectionMap.get(sectionId);
168	                if (oldSection != null) {
169	                    if (sectionMetaChanged(oldSection, newSection)) {
170	                        forkSectionReplaceTemplate(oldSection, newSection, saveBO.getType());
171	                    } else {
172	                        HseSectionEntity sectionEntity = new HseSectionEntity();
173	                        sectionEntity.setId(oldSection.getId());
174	                        BeanUtil.copyProperties(newSection, sectionEntity);
175	                        sectionEntity.setSectionId(sectionId);
176	                        sectionEntity.setType(saveBO.getType());
177	                        this.updateById(sectionEntity);
178	                        syncItems(newSection.getItems(), sectionId);
179	                    }
180	                }
181	            }
182	        }
183	
184	        // 删除不在新列表中的旧分区
185	        List<Long> newSectionIds =
186	                newSections.stream().map(SectionSaveBO::getSectionId).filter(id -> id != null).collect(Collectors.toList());
187	
188	        if (CollectionUtils.isNotEmpty(oldSections)) {
189	            List<HseSectionEntity> toDeleteSections = oldSections.stream()
190	                    .filter(old -> !newSectionIds.contains(old.getSectionId()))
191	                    .collect(Collectors.toList());
192	
193	            if (CollectionUtils.isNotEmpty(toDeleteSections)) {
194	                List<Long> deleteIds =
