232	    /**
233	     * 同步检查项（增删改）- 用于修改分区时
234	     */
235	    private void syncItems(List<InspectionItemSaveBO> newItems, Long sectionId) {
236	        // 查询该分区下的所有旧检查项
237	        LambdaQueryWrapper<HseInspectionDormSetupEntity> queryWrapper = new LambdaQueryWrapper<>();
238	        queryWrapper.eq(HseInspectionDormSetupEntity::getSectionId, sectionId);
239	        List<HseInspectionDormSetupEntity> oldItems = hseInspectionDormSetupService.list(queryWrapper);
240	
241	        // 将旧检查项转换为Map，key为dormSetupId
242	        Map<Long, HseInspectionDormSetupEntity> oldItemMap = oldItems.stream()
243	                .collect(Collectors.toMap(HseInspectionDormSetupEntity::getDormSetupId, item -> item, (v1, v2) -> v1));
244	
245	        // 处理新检查项
246	        if (CollectionUtils.isNotEmpty(newItems)) {
247	            List<Long> newItemIds = new ArrayList<>();
248	
249	            for (InspectionItemSaveBO newItemBO : newItems) {
250	                Long dormSetupId = newItemBO.getDormSetupId();
251	
252	                if (dormSetupId == null) {
253	                    // 新增检查项
254	                    HseInspectionDormSetupEntity newItem = new HseInspectionDormSetupEntity();
255	                    newItem.setSectionId(sectionId);
256	                    newItem.setDormSetupId(IdWorker.getId());
257	                    newItem.setName(newItemBO.getName());
258	                    newItem.setNameAr(newItemBO.getNameAr());
259	                    newItem.setOrgId(newItemBO.getOrgId());
260	                    newItem.setSort(newItemBO.getSort());
261	                    hseInspectionDormSetupService.save(newItem);
262	                } else {
263	                    HseInspectionDormSetupEntity oldItem = oldItemMap.get(dormSetupId);
264	                    if (oldItem != null) {
265	                        if (itemContentChanged(oldItem, newItemBO)) {
266	                            HseInspectionDormSetupEntity newItem = new HseInspectionDormSetupEntity();
267	                            newItem.setSectionId(sectionId);
268	                            newItem.setDormSetupId(IdWorker.getId());
269	                            newItem.setName(newItemBO.getName());
270	                            newItem.setNameAr(newItemBO.getNameAr());
271	                            newItem.setOrgId(newItemBO.getOrgId());
272	                            newItem.setSort(newItemBO.getSort());
273	                            hseInspectionDormSetupService.save(newItem);
274	                            newItemIds.add(newItem.getDormSetupId());
275	                        } else {
276	                            HseInspectionDormSetupEntity updateItem = new HseInspectionDormSetupEntity();
277	                            updateItem.setId(oldItem.getId());
278	                            updateItem.setDormSetupId(dormSetupId);
279	                            updateItem.setSectionId(sectionId);
280	                            updateItem.setName(newItemBO.getName());
281	                            updateItem.setNameAr(newItemBO.getNameAr());
282	                            updateItem.setOrgId(newItemBO.getOrgId());
283	                            updateItem.setSort(newItemBO.getSort());
284	                            hseInspectionDormSetupService.updateById(updateItem);
285	                            newItemIds.add(dormSetupId);
286	                        }
287	                    }
288	                }
289	            }
290	
291	            // 删除不在新列表中的旧检查项
292	            if (CollectionUtils.isNotEmpty(oldItems)) {
293	                List<HseInspectionDormSetupEntity> toDeleteItems = oldItems.stream()
294	                        .filter(old -> !newItemIds.contains(old.getDormSetupId()))
295	                        .collect(Collectors.toList());
296	
297	                if (CollectionUtils.isNotEmpty(toDeleteItems)) {
298	                    List<Long> deleteIds =
299	                            toDeleteItems.stream().map(HseInspectionDormSetupEntity::getId).collect(Collectors.toList());
300	                    hseInspectionDormSetupService.removeByIds(deleteIds);
301	                }
302	            }
303	        } else {
304	            // 新列表为空，删除所有旧检查项
305	            if (CollectionUtils.isNotEmpty(oldItems)) {
306	                List<Long> deleteIds =
307	                        oldItems.stream().map(HseInspectionDormSetupEntity::getId).collect(Collectors.toList());
308	                hseInspectionDormSetupService.removeByIds(deleteIds);
309	            }
310	        }
311	    }
