313	    private void validateSectionSavePayload(SectionSaveTypeBO saveBO) {
314	        if (saveBO == null) {
315	            throw new BusinessException(CommonError.PARAM_ERROR.getCode(), "Request body is required.");
316	        }
317	        if (saveBO.getType() == null) {
318	            throw new BusinessException(CommonError.PARAM_ERROR.getCode(),
319	                    "Inspection form type is missing. Please reopen the form tab and try again.");
320	        }
321	        if (saveBO.getSections() == null || saveBO.getSections().isEmpty()) {
322	            throw new BusinessException(CommonError.PARAM_ERROR.getCode(),
323	                    "Please add at least one inspection section before saving.");
324	        }
325	        List<SectionSaveBO> sections = saveBO.getSections();
326	        for (int si = 0; si < sections.size(); si++) {
327	            SectionSaveBO section = sections.get(si);
328	            int sectionNo = si + 1;
329	            if (section == null) {
330	                throw new BusinessException(CommonError.PARAM_ERROR.getCode(),
331	                        "Section " + sectionNo + " is empty. Remove the blank row or fill it in.");
332	            }
333	            if (StringUtils.isBlank(section.getName()) && StringUtils.isBlank(section.getNameAr())) {
334	                throw new BusinessException(CommonError.PARAM_ERROR.getCode(),
335	                        "Section " + sectionNo + ": please enter the section title in English and/or Arabic.");
336	            }
337	            List<InspectionItemSaveBO> items = section.getItems();
338	            if (CollectionUtils.isEmpty(items)) {
339	                throw new BusinessException(CommonError.PARAM_ERROR.getCode(),
340	                        "Section " + sectionNo + " (" + abbreviateLabel(section) + "): please add at least one inspection item.");
341	            }
342	            for (int ii = 0; ii < items.size(); ii++) {
343	                InspectionItemSaveBO item = items.get(ii);
344	                int itemNo = ii + 1;
345	                if (item == null) {
346	                    throw new BusinessException(CommonError.PARAM_ERROR.getCode(),
347	                            "Section " + sectionNo + ", item " + itemNo + " is empty. Remove the blank row or fill it in.");
348	                }
349	                if (StringUtils.isBlank(item.getName()) && StringUtils.isBlank(item.getNameAr())) {
350	                    throw new BusinessException(CommonError.PARAM_ERROR.getCode(),
351	                            "Section " + sectionNo + ", item " + itemNo + ": please enter the inspection item text in English and/or Arabic.");
352	                }
353	                if (item.getOrgId() == null) {
354	                    throw new BusinessException(CommonError.PARAM_ERROR.getCode(),
355	                            "Section " + sectionNo + ", item " + itemNo + ": please select a responsible department.");
356	                }
357	                if (item.getSort() == null) {
358	                    throw new BusinessException(CommonError.PARAM_ERROR.getCode(),
359	                            "Section " + sectionNo + ", item " + itemNo + ": sort is required.");
360	                }
361	            }
362	        }
363	    }
364	
365	    private static String abbreviateLabel(SectionSaveBO section) {
366	        String label = StringUtils.isNotBlank(section.getName()) ? section.getName().trim()
367	                : (StringUtils.isNotBlank(section.getNameAr()) ? section.getNameAr().trim() : null);
368	        if (label == null) {
369	            return "untitled";
370	        }
371	        return label.length() > 48 ? label.substring(0, 45) + "..." : label;
372	    }
