374	    /**
375	     * 同一保存请求中分区英文名不可重复；分区阿拉伯名（非空时）不可重复；各分区下检查项英文名不可重复、阿拉伯名（非空时）不可重复。
376	     */
377	    private void validateSectionAndItemNames(List<SectionSaveBO> sections) {
378	        Set<String> sectionNames = new HashSet<>();
379	        Set<String> sectionNameArs = new HashSet<>();
380	        for (SectionSaveBO section : sections) {
381	            String name = StringUtils.trimToEmpty(section.getName());
382	            if (StringUtils.isNotBlank(name) && !sectionNames.add(name)) {
383	                throw new BusinessException(CommonError.PARAM_ERROR.getCode(),
384	                        "Two sections use the same English title \"" + name + "\". Please make each section title unique.");
385	            }
386	            String nameAr = StringUtils.trimToEmpty(section.getNameAr());
387	            if (StringUtils.isNotEmpty(nameAr) && !sectionNameArs.add(nameAr)) {
388	                throw new BusinessException(CommonError.PARAM_ERROR.getCode(),
389	                        "Two sections use the same Arabic title \"" + nameAr + "\". Please make each section title unique.");
390	            }
391	            validateItemNames(section.getItems());
392	        }
393	    }
