395	    private void validateItemNames(List<InspectionItemSaveBO> items) {
396	        if (CollectionUtils.isEmpty(items)) {
397	            return;
398	        }
399	        Set<String> names = new HashSet<>();
400	        Set<String> nameArs = new HashSet<>();
401	        for (InspectionItemSaveBO item : items) {
402	            String name = StringUtils.trimToEmpty(item.getName());
403	            if (StringUtils.isNotBlank(name) && !names.add(name)) {
404	                throw new BusinessException(CommonError.PARAM_ERROR.getCode(),
405	                        "Within one section, two items share the same English text \"" + name + "\". Please make each item unique.");
406	            }
407	            String nameAr = StringUtils.trimToEmpty(item.getNameAr());
408	            if (StringUtils.isNotEmpty(nameAr) && !nameArs.add(nameAr)) {
409	                throw new BusinessException(CommonError.PARAM_ERROR.getCode(),
410	                        "Within one section, two items share the same Arabic text \"" + nameAr + "\". Please make each item unique.");
411	            }
412	        }
413	    }
