415	    private boolean sectionMetaChanged(HseSectionEntity old, SectionSaveBO neu) {
416	        return !StringUtils.equals(StringUtils.trimToEmpty(old.getName()), StringUtils.trimToEmpty(neu.getName()))
417	                || !StringUtils.equals(StringUtils.trimToEmpty(old.getNameAr()), StringUtils.trimToEmpty(neu.getNameAr()))
418	                || !Objects.equals(old.getOrgId(), neu.getOrgId());
419	    }
