421	    private boolean itemContentChanged(HseInspectionDormSetupEntity old, InspectionItemSaveBO neu) {
422	        return !StringUtils.equals(StringUtils.trimToEmpty(old.getName()), StringUtils.trimToEmpty(neu.getName()))
423	                || !StringUtils.equals(StringUtils.trimToEmpty(old.getNameAr()), StringUtils.trimToEmpty(neu.getNameAr()))
424	                || !Objects.equals(old.getOrgId(), neu.getOrgId());
425	    }
