427	    /**
428	     * 软删原分区及其下检查项，按当前表单新建分区与新检查项（新 sectionId），历史作答仍引用旧 id 可查已删行展示旧文案。
429	     */
430	    private void forkSectionReplaceTemplate(HseSectionEntity oldSection, SectionSaveBO newSection, Integer type) {
431	        Long oldSectionId = oldSection.getSectionId();
432	        LambdaQueryWrapper<HseInspectionDormSetupEntity> itemQw = new LambdaQueryWrapper<>();
433	        itemQw.eq(HseInspectionDormSetupEntity::getSectionId, oldSectionId);
434	        List<HseInspectionDormSetupEntity> oldItems = hseInspectionDormSetupService.list(itemQw);
435	        if (CollectionUtils.isNotEmpty(oldItems)) {
436	            hseInspectionDormSetupService.removeBatchByIds(
437	                    oldItems.stream().map(HseInspectionDormSetupEntity::getId).collect(Collectors.toList()));
438	        }
439	        this.removeById(oldSection.getId());
440	
441	        HseSectionEntity sectionEntity = new HseSectionEntity();
442	        BeanUtil.copyProperties(newSection, sectionEntity);
443	
444	
445	        sectionEntity.setId(null);
446	        sectionEntity.setSectionId(IdWorker.getId());
447	        sectionEntity.setType(type);
448	        this.save(sectionEntity);
449	        saveItems(newSection.getItems(), sectionEntity.getSectionId());
450	    }
