29	    @Override
30	    public List<HseInspectionDormSetupEntity> listByDormSetupIdsIncludeDeleted(Collection<Long> dormSetupIds) {
31	        if (dormSetupIds == null || dormSetupIds.isEmpty()) {
32	            return Collections.emptyList();
33	        }
34	        List<Long> ids = dormSetupIds.stream().filter(Objects::nonNull).distinct().collect(Collectors.toList());
35	        if (ids.isEmpty()) {
36	            return Collections.emptyList();
37	        }
38	        List<HseInspectionDormLookupRow> rows = baseMapper.selectByDormSetupIdsIncludeDeleted(ids);
39	        if (CollectionUtils.isEmpty(rows)) {
40	            return Collections.emptyList();
41	        }
42	        List<HseInspectionDormSetupEntity> out = new ArrayList<>(rows.size());
43	        for (HseInspectionDormLookupRow row : rows) {
44	            HseInspectionDormSetupEntity e = new HseInspectionDormSetupEntity();
45	            e.setId(row.getId());
46	            e.setDormSetupId(row.getDormSetupId());
47	            e.setSectionId(row.getSectionId());
48	            e.setOrgId(row.getOrgId());
49	            e.setName(row.getName());
50	            e.setNameAr(row.getNameAr());
51	            out.add(e);
52	        }
53	        return out;
54	    }
55	}
